sql:
SELECT age, total_earnings
FROM horses
ORDER BY total_earnings DESC;

external_knowledge:
- "seasoned navigators of the equine racetracks" refers to experienced jockeys;
- "origins" means the nationality of the jockeys;
- "duration of their voyages across the sands" is a metaphor for the years of experience of the jockeys;
- "steeds they wield" is a metaphor for the horses ridden by the jockeys;
- "the name of the track they're about to conquer" refers to the race name.

sql:
SELECT jockey_name, total_earnings
FROM jockeys
WHERE total_earnings = (SELECT MAX(total_earnings) FROM jockeys);

SELECT trainer_name 
FROM trainers 
WHERE number_of_wins = (
    SELECT MAX(number_of_wins) 
    FROM trainers
);

SELECT total_earnings 
FROM trainers 
WHERE trainer_id = 0;

SELECT j.jockey_id, j.jockey_name, j.license_number, j.nationality, j.date_of_birth, j.years_of_experience, j.number_of_wins, j.total_earnings, j.weight
FROM jockeys j
WHERE j.jockey_id IN (SELECT rp.jockey_id FROM race_participants rp);

SELECT trainer_name, number_of_wins 
FROM trainers 
WHERE number_of_wins = (SELECT MAX(number_of_wins) FROM trainers);
